import pg from 'pg';
const { Client } = pg;

const DATABASE_URL = 'postgres://neondb_owner:npg_uitam2Spqb9T@ep-divine-glade-adt3sbj8-pooler.c-2.us-east-1.aws.neon.tech/neondb?sslmode=require';

async function main() {
  const client = new Client({ connectionString: DATABASE_URL });
  await client.connect();
  console.log('Connected to Neon database.');
  try {
    // Drop the unique constraint names commonly generated by postgres/drizzle
    await client.query('ALTER TABLE exam_sessions DROP CONSTRAINT IF EXISTS exam_sessions_access_code_unique;');
    await client.query('ALTER TABLE exam_sessions DROP CONSTRAINT IF EXISTS exam_sessions_access_code_key;');
    console.log('Unique constraint dropped successfully from exam_sessions table.');
  } catch (err) {
    console.error('Failed to drop constraint:', err.message);
  } finally {
    await client.end();
  }
}

main().catch(err => {
  console.error('Script error:', err);
});
